-- Running total: ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
SELECT id, val, SUM(val) OVER (ORDER BY id ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS running FROM metrics;

-- Moving average: ROWS BETWEEN 2 PRECEDING AND CURRENT ROW
SELECT id, val, AVG(val) OVER (PARTITION BY category ORDER BY id ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) AS moving_avg FROM metrics;

-- Cumulative: RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
SELECT id, val, SUM(val) OVER (PARTITION BY dept ORDER BY ts RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS cumulative FROM sales;

-- Single bound: ROWS UNBOUNDED PRECEDING
SELECT id, val, SUM(val) OVER (ORDER BY id ROWS UNBOUNDED PRECEDING) AS total FROM metrics;

-- Full window: ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
SELECT id, val, AVG(val) OVER (PARTITION BY dept ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) AS dept_avg FROM sales;
